			}
			data, err := loadJSONFile(dataFile)
			if err != nil {
				return fmt.Errorf("failed to load data file: %w", err)
			}
			token, err := getOrRefreshCommandToken(cmd, configManager, useOrg)
			if err != nil {
				return err
